<h1 class="wp-block-heading" style="font-size:clamp(32px,4vw,48px)">Сколько стоит сайт в Италии: честные цифры</h1>
<!-- /wp:heading -->
<!-- wp:html -->
<figure class="wp-block-image size-large" style="margin:8px 0 8px"><img src="/wp-content/themes/remarka-studio/assets/img/blog/batch5-cena-cover.svg" alt="Сколько стоит сайт в Италии: диапазоны от визитки за 1900 евро до магазина за 14000 евро" loading="lazy" width="1200" height="630" style="max-width:100%;height:auto;display:block;border:1px solid var(--sr-bordo)"/></figure>
